import React, { useState } from 'react';

const App = () => {
  const [credits, setCredits] = useState(0);
  const [modelName, setModelName] = useState('Model A');

  const handleCreditIncrement = () => setCredits(credits + 1);
  const handleCreditDecrement = () => setCredits(credits - 1);

  return (
    <div className="min-h-screen bg-[#090a0f] text-white p-4 flex items-center justify-center">
      <div className="bg [#B7D7CD] p-4 rounded-md w-3/4 text-center">
        <h2 className="text-lg text-[#C06C88]">{modelName}</h2>
        <p className="text-sm text-[#B7D7CD]">Credits: {credits}</p>
        <div className="flex justify-around mt-4">
          <button className="bg-[#C06C88] p-2 rounded-lg" onClick={handleCreditIncrement}>+</button>
          <button className="bg-[#C06C88] p-2 rounded-lg" onClick={handleCreditDecrement}>-</button>
        </div>
      </div>
    </div>
  );
};

export default App;
